"""Arithmetic expression evaluator.

Implements a single public function, ``evaluate``, using a hand-written
tokenizer and recursive-descent parser. No ``eval``, ``exec`` or ``ast``.
"""


def _tokenize(expr):
    tokens = []
    i = 0
    n = len(expr)
    digits = "0123456789."
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        if c in digits:
            j = i
            while j < n and expr[j] in digits:
                j += 1
            num_str = expr[i:j]
            try:
                value = float(num_str)
            except ValueError:
                raise ValueError("invalid number literal: %r" % num_str)
            tokens.append(("num", value))
            i = j
        elif c == "*":
            if i + 1 < n and expr[i + 1] == "*":
                tokens.append(("op", "**"))
                i += 2
            else:
                tokens.append(("op", "*"))
                i += 1
        elif c in "+-/":
            tokens.append(("op", c))
            i += 1
        elif c == "(":
            tokens.append(("lparen", "("))
            i += 1
        elif c == ")":
            tokens.append(("rparen", ")"))
            i += 1
        else:
            raise ValueError("illegal character: %r" % c)
    return tokens


class _Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def _peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def _advance(self):
        tok = self.tokens[self.pos]
        self.pos += 1
        return tok

    def parse(self):
        value = self._expr()
        if self.pos != len(self.tokens):
            raise ValueError("unexpected trailing input")
        return value

    def _expr(self):
        value = self._term()
        while True:
            tok = self._peek()
            if tok is not None and tok[0] == "op" and tok[1] in ("+", "-"):
                self._advance()
                right = self._term()
                value = value + right if tok[1] == "+" else value - right
            else:
                break
        return value

    def _term(self):
        value = self._unary()
        while True:
            tok = self._peek()
            if tok is not None and tok[0] == "op" and tok[1] in ("*", "/"):
                self._advance()
                right = self._unary()
                value = value * right if tok[1] == "*" else value / right
            else:
                break
        return value

    def _unary(self):
        tok = self._peek()
        if tok is not None and tok[0] == "op" and tok[1] in ("+", "-"):
            self._advance()
            operand = self._unary()
            return -operand if tok[1] == "-" else operand
        return self._power()

    def _power(self):
        base = self._atom()
        tok = self._peek()
        if tok is not None and tok[0] == "op" and tok[1] == "**":
            self._advance()
            exponent = self._unary()
            return base ** exponent
        return base

    def _atom(self):
        tok = self._peek()
        if tok is None:
            raise ValueError("unexpected end of input")
        if tok[0] == "num":
            self._advance()
            return tok[1]
        if tok[0] == "lparen":
            self._advance()
            value = self._expr()
            closing = self._peek()
            if closing is None or closing[0] != "rparen":
                raise ValueError("unbalanced parentheses")
            self._advance()
            return value
        raise ValueError("unexpected token: %r" % (tok[1],))


def evaluate(expr: str) -> float:
    if not isinstance(expr, str):
        raise ValueError("expression must be a string")
    tokens = _tokenize(expr)
    if not tokens:
        raise ValueError("empty expression")
    result = _Parser(tokens).parse()
    return float(result)
